func PostMessageTo(cur realm, fromID uint64, toID uint64, message string) {
	sender, ok := dragons[fromID]
	if !ok {
		panic("sender dragon not found")
	}
	caller := Address(runtime.PreviousRealm().Address())
	if sender.Owner != caller {
		panic("not owner")
	}

	if len(message) > 280 {
		panic("message too long")
	}
	if !IsDragon(toID) {
		panic("target dragon not found")
	}
	if fromID == toID {
		panic("cannot post to self")
	}

	target := dragons[toID]
	target.Messages = append(target.Messages, message)
	if len(target.Messages) > 100 {
		target.Messages = target.Messages[1:]
	}
}

func GetMessages(cur realm, id uint64) []string {
	d, ok := dragons[id]
	if !ok {
		panic("dragon not found")
	}
	caller := Address(runtime.PreviousRealm().Address())
	if d.Owner != caller {
		panic("not owner")
	}
	result := make([]string, len(d.Messages))
	copy(result, d.Messages)
	return result
}

func ClearMessages(id uint64) {
	d, ok := dragons[id]
	if !ok {
		panic("dragon not found")
	}
	caller := Address(runtime.PreviousRealm().Address())
	if d.Owner != caller {
		panic("not owner")
	}
	d.Messages = d.Messages[:0]
}

func GetDragon(id uint64) Dragon {
	d, ok := dragons[id]
	if !ok {
		panic("dragon not found")
	}
	return *d
}

func IsDragon(id uint64) bool {
	_, ok := dragons[id]
	return ok
}

func SendPearlsTo(fromID uint64, toID uint64, amount uint64) {
	d, ok := dragons[fromID]
	if !ok {
		panic("dragon not found")
	}

	caller := Address(runtime.PreviousRealm().Address())
	if d.Owner != caller {
		panic("not owner")
	}

	if amount == 0 {
		panic("amount must be > 0")
	}
	if !IsDragon(toID) {
		panic("target is not a dragon")
	}
	if d.Pearls < amount {
		panic("not enough pearls")
	}

	d.Pearls -= amount
	dragons[toID].Pearls += amount
}

func QueryConstitution(fromID uint64, targetID uint64) string {
	d, ok := dragons[fromID]
	if !ok {
		panic("dragon not found")
	}

	caller := Address(runtime.PreviousRealm().Address())
	if d.Owner != caller {
		panic("not owner")
	}

	if !IsDragon(targetID) {
		panic("target is not a dragon")
	}
	return dragons[targetID].Constitution
}

func GetMyPearls(id uint64) uint64 {
	d, ok := dragons[id]
	if !ok {
		panic("dragon not found")
	}

	caller := Address(runtime.PreviousRealm().Address())
	if d.Owner != caller {
		panic("not owner")
	}
	return d.Pearls
}

func ListAllDragons() map[string]any {
    if dragons == nil || len(dragons) == 0 {
        return make(map[string]any)
    }

    result := make(map[string]any)

    for addr, d := range dragons {
        if d == nil {
            continue
        }
        // Convert to plain map so JSON output is predictable
        dragonMap := map[string]any{
            "ID":           d.ID,           // assume these fields exist on Dragon
            "Owner":        d.Owner,
            "Level":        d.Level,
            "Pearls":       d.Pearls,
            "Constitution": d.Constitution,
            // add any other fields your frontend uses (renderMyDragons / renderAllDragons)
        }
        result[string(addr)] = dragonMap   // Address → string key
    }

    return result
}

