package fee_split

import (
	"strconv"
	"strings"
)

type Split struct {
	Owner          string
	Recipients     []string
	Shares         []uint64
	Balances       map[string]uint64
	TotalDeposited uint64
	TotalClaimed   uint64
	Frozen         bool
	Archived       bool
}

const (
	MaxRecipients     = 20
	MaxSplitsPerOwner = 10
	MaxSplitsGlobal   = 500
)

var (
	splits      map[string]*Split
	splitIDs    []string
	ownerSplits map[string]int
	nextID      int
)

func init() {
	splits = make(map[string]*Split)
	splitIDs = []string{}
	ownerSplits = make(map[string]int)
	nextID = 1
}

func formatPct(bp uint64) string {
	whole := strconv.FormatUint(bp/100, 10)
	frac := strconv.FormatUint(bp%100, 10)
	if len(frac) == 1 {
		frac = "0" + frac
	}
	return whole + "." + frac + "%"
}

func mustGetSplit(id string) *Split {
	s, ok := splits[id]
	if !ok {
		panic("split not found: " + id)
	}
	return s
}

func mustGetActive(id string) *Split {
	s := mustGetSplit(id)
	if s.Archived {
		panic("split is archived: " + id)
	}
	return s
}

func boolStr(v bool) string {
	if v {
		return "yes"
	}
	return "no"
}

func parseBasisPoints(raw string) []uint64 {
	parts := strings.Split(raw, ",")
	out := make([]uint64, len(parts))
	var total uint64
	for i, s := range parts {
		v, err := strconv.Atoi(strings.TrimSpace(s))
		if err != nil || v <= 0 {
			panic("invalid share value: " + strings.TrimSpace(s))
		}
		out[i] = uint64(v)
		total += uint64(v)
	}
	if total != 10000 {
		panic("shares must sum to 10000 basis points, got " + strconv.FormatUint(total, 10))
	}
	return out
}

func parseAddresses(raw string) []string {
	parts := strings.Split(raw, ",")
	out := make([]string, len(parts))
	for i, r := range parts {
		addr := strings.TrimSpace(r)
		if addr == "" {
			panic("empty recipient address at position " + strconv.Itoa(i))
		}
		out[i] = addr
	}
	return out
}

func CreateSplit(_ realm, owner, recipientList, shareList string) string {
	if len(splits) >= MaxSplitsGlobal {
		panic("global split limit reached")
	}
	if owner == "" {
		panic("owner must not be empty")
	}
	if ownerSplits[owner] >= MaxSplitsPerOwner {
		panic("per-owner split limit reached")
	}

	recipients := parseAddresses(recipientList)
	shares := parseBasisPoints(shareList)

	if len(recipients) != len(shares) {
		panic("recipients and shares must have the same length")
	}
	if len(recipients) == 0 {
		panic("at least one recipient is required")
	}
	if len(recipients) > MaxRecipients {
		panic("too many recipients (max " + strconv.Itoa(MaxRecipients) + ")")
	}

	seen := make(map[string]bool)
	for _, r := range recipients {
		if seen[r] {
			panic("duplicate recipient: " + r)
		}
		seen[r] = true
	}

	id := "split_" + strconv.Itoa(nextID)
	nextID++

	balances := make(map[string]uint64)
	for _, r := range recipients {
		balances[r] = 0
	}

	splits[id] = &Split{
		Owner:      owner,
		Recipients: recipients,
		Shares:     shares,
		Balances:   balances,
	}
	splitIDs = append(splitIDs, id)
	ownerSplits[owner]++
	return id
}

func Deposit(_ realm, splitID string, amount uint64) {
	s := mustGetActive(splitID)
	if s.Frozen {
		panic("split is frozen")
	}
	if amount == 0 {
		panic("amount must be greater than zero")
	}

	s.TotalDeposited += amount

	dustIdx := 0
	for i := 1; i < len(s.Shares); i++ {
		if s.Shares[i] > s.Shares[dustIdx] {
			dustIdx = i
		}
	}

	var distributed uint64
	for i, r := range s.Recipients {
		share := (amount * s.Shares[i]) / 10000
		s.Balances[r] += share
		distributed += share
	}

	dust := amount - distributed
	if dust > 0 {
		s.Balances[s.Recipients[dustIdx]] += dust
	}
}

func Claim(_ realm, splitID, addr string) uint64 {
	s := mustGetActive(splitID)
	bal, exists := s.Balances[addr]
	if !exists {
		panic("not a recipient of this split")
	}
	if bal == 0 {
		panic("nothing to claim")
	}
	s.Balances[addr] = 0
	s.TotalClaimed += bal
	return bal
}

func Freeze(_ realm, splitID, owner string) {
	s := mustGetActive(splitID)
	if owner != s.Owner {
		panic("only the owner can freeze")
	}
	s.Frozen = true
}

func Archive(_ realm, splitID, owner string) {
	s := mustGetActive(splitID)
	if owner != s.Owner {
		panic("only the owner can archive")
	}
	for _, r := range s.Recipients {
		if s.Balances[r] > 0 {
			panic("cannot archive: outstanding balance for " + r)
		}
	}
	s.Archived = true
	ownerSplits[s.Owner]--
	if ownerSplits[s.Owner] <= 0 {
		delete(ownerSplits, s.Owner)
	}
	for i, id := range splitIDs {
		if id == splitID {
			splitIDs = append(splitIDs[:i], splitIDs[i+1:]...)
			break
		}
	}
}

func GetSplitInfo(splitID string) string {
	s := mustGetSplit(splitID)
	var b strings.Builder
	b.WriteString("Split: " + splitID + "\n")
	b.WriteString("Owner: " + s.Owner + "\n")
	b.WriteString("Frozen: " + boolStr(s.Frozen) + "\n")
	b.WriteString("Deposited: " + strconv.FormatUint(s.TotalDeposited, 10) + "\n")
	b.WriteString("Claimed: " + strconv.FormatUint(s.TotalClaimed, 10) + "\n")
	for i, r := range s.Recipients {
		b.WriteString("  " + r + "  " + formatPct(s.Shares[i]) + "  claimable: " + strconv.FormatUint(s.Balances[r], 10) + "\n")
	}
	return b.String()
}

func GetClaimable(splitID, addr string) uint64 {
	s := mustGetSplit(splitID)
	return s.Balances[addr]
}

func Render(path string) string {
	if splits == nil || len(splits) == 0 {
		return "# Fee Split\n\nNo active splits.\n"
	}

	var b strings.Builder
	b.WriteString("# Fee Split\n\n")

	for _, id := range splitIDs {
		s := splits[id]
		if s == nil {
			continue
		}
		b.WriteString("## " + id + "\n\n")
		b.WriteString("Owner: " + s.Owner + "\n")
		b.WriteString("Frozen: " + boolStr(s.Frozen) + "\n")
		b.WriteString("Deposited: " + strconv.FormatUint(s.TotalDeposited, 10) + "\n")
		b.WriteString("Claimed: " + strconv.FormatUint(s.TotalClaimed, 10) + "\n")
		if len(s.Recipients) > 0 {
			for i, r := range s.Recipients {
				b.WriteString("  " + r + "  " + formatPct(s.Shares[i]) + "  claimable: " + strconv.FormatUint(s.Balances[r], 10) + "\n")
			}
		}
		b.WriteString("\n")
	}
	return b.String()
}

package permission_registry

import (
	"sort"
	"strings"
)

var (
	resources     map[string]string
	resourceNames []string
	permissions   map[string]map[string]map[string]bool
	permList      map[string][]string
)

func init() {
	resources = make(map[string]string)
	resourceNames = []string{}
	permissions = make(map[string]map[string]map[string]bool)
	permList = make(map[string][]string)
}

func mustBeAdmin(resource, admin string) {
	stored, exists := resources[resource]
	if !exists {
		panic("resource not found: " + resource)
	}
	if admin != stored {
		panic("permission denied: not admin of " + resource)
	}
}

func CreateResource(_ realm, admin, resourceName string) {
	if resourceName == "" {
		panic("resource name must not be empty")
	}
	if admin == "" {
		panic("admin must not be empty")
	}
	if _, exists := resources[resourceName]; exists {
		panic("resource already exists: " + resourceName)
	}
	resources[resourceName] = admin
	resourceNames = append(resourceNames, resourceName)
	permissions[resourceName] = make(map[string]map[string]bool)
	permList[resourceName] = []string{}
}

func Grant(_ realm, admin, resourceName, permission, addr string) {
	mustBeAdmin(resourceName, admin)
	if permission == "" {
		panic("permission name must not be empty")
	}
	if addr == "" {
		panic("address must not be empty")
	}
	perms := permissions[resourceName]
	if perms[permission] == nil {
		perms[permission] = make(map[string]bool)
		permList[resourceName] = append(permList[resourceName], permission)
	}
	if perms[permission][addr] {
		panic("permission already granted")
	}
	perms[permission][addr] = true
}

func Revoke(_ realm, admin, resourceName, permission, addr string) {
	mustBeAdmin(resourceName, admin)
	perms := permissions[resourceName]
	if perms[permission] == nil || !perms[permission][addr] {
		panic("permission not granted")
	}
	delete(perms[permission], addr)
}

func Has(resourceName, permission, addr string) bool {
	perms, exists := permissions[resourceName]
	if !exists {
		return false
	}
	holders := perms[permission]
	if holders == nil {
		return false
	}
	return holders[addr]
}

func GetAdmin(resourceName string) string {
	admin, exists := resources[resourceName]
	if !exists {
		return "not found"
	}
	return admin
}

func ListResources() string {
	if len(resourceNames) == 0 {
		return "none"
	}
	return strings.Join(resourceNames, ", ")
}

func Render(path string) string {
	if len(resources) == 0 {
		return "# Permission Registry\n\nNo resources registered.\n"
	}
	var b strings.Builder
	b.WriteString("# Permission Registry\n\n")
	for _, name := range resourceNames {
		admin := resources[name]
		b.WriteString("## " + name + "\n\n")
		b.WriteString("**Admin:** `" + admin + "`\n\n")
		perms, exists := permissions[name]
		if !exists || len(perms) == 0 {
			b.WriteString("_No permissions defined._\n\n")
			continue
		}
		b.WriteString("| Permission | Addresses |\n")
		b.WriteString("|------------|-----------|\n")
		for _, perm := range permList[name] {
			holders := perms[perm]
			if holders == nil || len(holders) == 0 {
				continue
			}
			var addrs []string
			for addr := range holders {
				if holders[addr] {
					addrs = append(addrs, addr)
				}
			}
			sort.Strings(addrs)
			for i, a := range addrs {
				addrs[i] = "`" + a + "`"
			}
			b.WriteString("| " + perm + " | " + strings.Join(addrs, ", ") + " |\n")
		}
		b.WriteString("\n")
	}
	return b.String()
}

package service_registry

import (
	"strconv"
	"strings"
)

type Service struct {
	Name        string
	Owner       string
	Description string
	ServiceType string
}

var (
	services map[string]*Service
	names    []string
)

func init() {
	services = make(map[string]*Service)
	names = []string{}
}

func mustGet(name string) *Service {
	svc, ok := services[name]
	if !ok {
		panic("service not found: " + name)
	}
	return svc
}

func RegisterService(_ realm, owner, name, description, serviceType string) {
	if name == "" {
		panic("name must not be empty")
	}
	if owner == "" {
		panic("owner must not be empty")
	}
	if _, exists := services[name]; exists {
		panic("service already registered: " + name)
	}
	services[name] = &Service{
		Name:        name,
		Owner:       owner,
		Description: description,
		ServiceType: serviceType,
	}
	names = append(names, name)
}

func UpdateService(_ realm, owner, name, description, serviceType string) {
	svc := mustGet(name)
	if owner != svc.Owner {
		panic("only the owner can update")
	}
	if description != "" {
		svc.Description = description
	}
	if serviceType != "" {
		svc.ServiceType = serviceType
	}
}

func Deregister(_ realm, owner, name string) {
	svc := mustGet(name)
	if owner != svc.Owner {
		panic("only the owner can deregister")
	}
	delete(services, name)
	for i, n := range names {
		if n == name {
			names = append(names[:i], names[i+1:]...)
			break
		}
	}
}

func GetService(name string) string {
	svc := mustGet(name)
	return "Name: " + svc.Name + " | Owner: " + svc.Owner + " | Type: " + svc.ServiceType + " | " + svc.Description
}

func ListServices() string {
	if len(names) == 0 {
		return "none"
	}
	return strings.Join(names, ", ")
}

func Render(path string) string {
	if len(services) == 0 {
		return "# Service Registry\n\nNo services registered.\n"
	}
	var b strings.Builder
	b.WriteString("# Service Registry\n\n")
	b.WriteString("**Total:** " + strconv.Itoa(len(services)) + "\n\n")
	b.WriteString("| Name | Type | Owner |\n")
	b.WriteString("|------|------|-------|\n")
	for _, name := range names {
		svc := services[name]
		if svc == nil {
			continue
		}
		b.WriteString("| " + svc.Name + " | " + svc.ServiceType + " | `" + svc.Owner + "` |\n")
	}
	return b.String()
}

package timelock_guardian

import (
	"strconv"
	"strings"
)

type Action struct {
	ID          string
	Creator     string
	Target      string
	Data        string
	CreatedAt   int64
	ExecuteAt   int64
	Executed    bool
	Cancelled   bool
}

var (
	actions   map[string]*Action
	actionIDs []string
	nextID    int
	curBlock  int64
)

func init() {
	actions = make(map[string]*Action)
	actionIDs = []string{}
	nextID = 1
	curBlock = 0
}

func mustGet(id string) *Action {
	a, ok := actions[id]
	if !ok {
		panic("action not found: " + id)
	}
	return a
}

func SetBlock(_ realm, height int64) {
	if height < 0 {
		panic("block height must be non-negative")
	}
	curBlock = height
}

func Schedule(_ realm, creator, target, data string, delay int64) string {
	if target == "" {
		panic("target must not be empty")
	}
	if delay <= 0 {
		panic("delay must be positive")
	}

	id := "action_" + strconv.Itoa(nextID)
	nextID++

	actions[id] = &Action{
		ID:        id,
		Creator:   creator,
		Target:    target,
		Data:      data,
		CreatedAt: curBlock,
		ExecuteAt: curBlock + delay,
	}
	actionIDs = append(actionIDs, id)
	return id
}

func Execute(_ realm, actionID string) string {
	a := mustGet(actionID)
	if a.Cancelled {
		panic("action is cancelled")
	}
	if a.Executed {
		panic("action already executed")
	}
	if curBlock < a.ExecuteAt {
		remaining := a.ExecuteAt - curBlock
		panic("too early: " + strconv.FormatInt(remaining, 10) + " blocks remaining")
	}
	a.Executed = true
	return "executed: " + actionID
}

func Cancel(_ realm, creator, actionID string) {
	a := mustGet(actionID)
	if a.Creator != creator {
		panic("only the creator can cancel")
	}
	if a.Executed {
		panic("cannot cancel executed action")
	}
	if a.Cancelled {
		panic("already cancelled")
	}
	a.Cancelled = true
}

func GetAction(actionID string) string {
	a := mustGet(actionID)
	status := "pending"
	if a.Cancelled {
		status = "cancelled"
	} else if a.Executed {
		status = "executed"
	} else if curBlock >= a.ExecuteAt {
		status = "ready"
	}
	return "ID: " + a.ID + " | Creator: " + a.Creator + " | Target: " + a.Target + " | Status: " + status
}

func IsReady(actionID string) bool {
	a, ok := actions[actionID]
	if !ok || a.Executed || a.Cancelled {
		return false
	}
	return curBlock >= a.ExecuteAt
}

func Render(path string) string {
	if len(actions) == 0 {
		return "# Timelock Guardian\n\nNo actions scheduled.\n"
	}
	var b strings.Builder
	b.WriteString("# Timelock Guardian\n\n")
	b.WriteString("**Block:** " + strconv.FormatInt(curBlock, 10) + "\n\n")

	for _, id := range actionIDs {
		a := actions[id]
		if a == nil {
			continue
		}
		status := "pending"
		if a.Cancelled {
			status = "cancelled"
		} else if a.Executed {
			status = "executed"
		} else if curBlock >= a.ExecuteAt {
			status = "**ready**"
		}
		b.WriteString("- **" + a.ID + "** | " + a.Target + " | " + status + "\n")
	}
	return b.String()
}

package upgrade_registry

import (
	"strconv"
	"strings"
)

type ContractEntry struct {
	Address    string
	Owner      string
	Name       string
	Deprecated bool
	Successor  string
}

var (
	entries    map[string]*ContractEntry
	entryAddrs []string
)

func init() {
	entries = make(map[string]*ContractEntry)
	entryAddrs = []string{}
}

func Register(_ realm, owner, contractAddr, name string) string {
	if contractAddr == "" || name == "" || owner == "" {
		panic("owner, contractAddr, and name must not be empty")
	}
	if _, exists := entries[contractAddr]; exists {
		panic("contract already registered: " + contractAddr)
	}
	entries[contractAddr] = &ContractEntry{
		Address: contractAddr,
		Owner:   owner,
		Name:    name,
	}
	entryAddrs = append(entryAddrs, contractAddr)
	return "registered " + name
}

func Deprecate(_ realm, owner, contractAddr, successorAddr string) string {
	entry, exists := entries[contractAddr]
	if !exists {
		panic("contract not found")
	}
	if entry.Owner != owner {
		panic("only the owner can deprecate")
	}
	if entry.Deprecated {
		panic("already deprecated")
	}
	if successorAddr == contractAddr {
		panic("successor cannot be self")
	}
	entry.Deprecated = true
	entry.Successor = successorAddr
	return "deprecated " + entry.Name
}

func GetLatest(contractAddr string) string {
	visited := make(map[string]bool)
	current := contractAddr
	for {
		entry, exists := entries[current]
		if !exists {
			return current
		}
		if !entry.Deprecated || entry.Successor == "" {
			return current
		}
		if visited[current] {
			return current
		}
		visited[current] = true
		current = entry.Successor
	}
}

func GetInfo(contractAddr string) string {
	entry, exists := entries[contractAddr]
	if !exists {
		panic("contract not found")
	}
	status := "active"
	if entry.Deprecated {
		status = "deprecated -> " + entry.Successor
	}
	return entry.Name + " | owner: " + entry.Owner + " | " + status
}

func Render(path string) string {
	if len(entries) == 0 {
		return "# Upgrade Registry\n\nNo contracts registered.\n"
	}
	var b strings.Builder
	b.WriteString("# Upgrade Registry\n\n")
	b.WriteString("**Total:** " + strconv.Itoa(len(entries)) + "\n\n")
	for _, addr := range entryAddrs {
		entry := entries[addr]
		if entry == nil {
			continue
		}
		line := "- **" + entry.Name + "** (`" + addr + "`) — owner: `" + entry.Owner + "`"
		if entry.Deprecated {
			line += " — DEPRECATED -> `" + entry.Successor + "`"
		}
		b.WriteString(line + "\n")
	}
	return b.String()
}
